function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return -1;
    }

    // 1. Calculate Prefix Maximums (LMax[i] = max(nums[0..i]))
    const lMax = new Array(n);
    lMax[0] = nums[0];
    for (let i = 1; i < n; i++) {
        lMax[i] = Math.max(lMax[i - 1], nums[i]);
    }

    // 2. Calculate Suffix Minimums (RMin[i] = min(nums[i..n-1]))
    const rMin = new Array(n);
    rMin[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        rMin[i] = Math.min(rMin[i + 1], nums[i]);
    }

    // 3. Find the smallest stable index
    for (let i = 0; i < n; i++) {
        // Instability = LMax[i] - RMin[i]
        const instability = lMax[i] - rMin[i];

        if (instability <= k) {
            return i;
        }
    }

    // 4. If no stable index is found
    return -1;
}

